Here's a modern MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new MockHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new MockHttpMessageHandler("", HttpStatusCode.NotFound);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com/missing", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        var handler = new MockHttpMessageHandler("data", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // Cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Lightweight fake handler — no mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---------|-----|
| **Async testing** | Return `async Task` — MSTest awaits it natively |
| **Timeouts** | `[Timeout(ms)]` cancels `TestContext.CancellationToken` on expiry |
| **CancellationToken propagation** | Pass `_testContext.CancellationToken` so the test aborts cleanly on timeout |
| **Cancellation verification** | Create a pre-cancelled `CancellationTokenSource` to prove the token is forwarded |
| **HttpClient testing** | Custom `HttpMessageHandler` — no mocking framework needed |
| **Constructor-injected TestContext** | MSTest 3.6+ pattern, enables `readonly` fields |
| **Sealed test class** | Modern MSTest best practice for performance |

The `[Timeout]` attribute is critical: if your async code hangs, the test will fail after the specified duration rather than blocking indefinitely.
